import axios from 'axios';

const API = axios.create({
  baseURL: process.env.REACT_APP_API_URL || '/api',
});

API.interceptors.request.use((config) => {
  const token = localStorage.getItem('sb_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

API.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('sb_token');
      localStorage.removeItem('sb_user');
      window.location.href = '/login';
    }
    return Promise.reject(err);
  }
);

// ── Auth ──────────────────────────────────────────────────────────────────────
export const authAPI = {
  register: (data) => API.post('/auth/register', data),
  login: (data) => API.post('/auth/login', data),
  getMe: () => API.get('/auth/me'),
  updateProfile: (data) => API.put('/auth/update-profile', data),
  changePassword: (data) => API.put('/auth/change-password', data),
};

// ── Providers ─────────────────────────────────────────────────────────────────
export const providerAPI = {
  getCategories: () => API.get('/providers/categories'),
  search: (params) => API.get('/providers/search', { params }),
  getTop: (params) => API.get('/providers/top', { params }),
  getById: (id) => API.get(`/providers/${id}`),
  getMyProfile: () => API.get('/providers/me'),
  createProfile: (data) => API.post('/providers/profile', data),
  updateProfile: (data) => API.put('/providers/profile', data),
  updateAvailability: (data) => API.put('/providers/availability', data),
  updateLiveLocation: (data) => API.put('/providers/live-location', data),
};

// ── Bookings ──────────────────────────────────────────────────────────────────
export const bookingAPI = {
  create: (data) => API.post('/bookings', data),
  getUserBookings: (params) => API.get('/bookings/user', { params }),
  getProviderBookings: (params) => API.get('/bookings/provider', { params }),
  getById: (id) => API.get(`/bookings/${id}`),
  updateStatus: (id, data) => API.put(`/bookings/${id}/status`, data),
};

// ── Chat ──────────────────────────────────────────────────────────────────────
export const chatAPI = {
  send: (data) => API.post('/chat/send', data),
  getConversation: (otherUserId, params) => API.get(`/chat/${otherUserId}`, { params }),
  getConversations: () => API.get('/chat/conversations'),
  getUnreadCount: () => API.get('/chat/unread'),
};

// ── Payments ──────────────────────────────────────────────────────────────────
export const paymentAPI = {
  createOrder: (data) => API.post('/payments/create-order', data),
  verify: (data) => API.post('/payments/verify', data),
  getByBooking: (bookingId) => API.get(`/payments/booking/${bookingId}`),
};

// ── Reviews ───────────────────────────────────────────────────────────────────
export const reviewAPI = {
  create: (data) => API.post('/reviews', data),
  getByProvider: (providerId, params) => API.get(`/reviews/provider/${providerId}`, { params }),
  addReply: (id, data) => API.put(`/reviews/${id}/reply`, data),
};

// ── Admin ─────────────────────────────────────────────────────────────────────
export const adminAPI = {
  getDashboard: () => API.get('/admin/dashboard'),
  getPendingProviders: () => API.get('/admin/providers/pending'),
  verifyProvider: (id, data) => API.put(`/admin/providers/${id}/verify`, data),
  getUsers: (params) => API.get('/admin/users', { params }),
  toggleUser: (id) => API.put(`/admin/users/${id}/toggle`),
  getBookings: (params) => API.get('/admin/bookings', { params }),
};

export default API;
